# ─── Audio helpers ────────────────────────────────────────────────────────────

def make_sound(freq, duration_ms, wave_type='square', volume=0.3):
    """Generate a pygame Sound object."""
    n = int(SAMPLE_RATE * duration_ms / 1000)
    t = np.linspace(0, duration_ms / 1000, n, endpoint=False)
    if wave_type == 'square':
        wave = np.sign(np.sin(2 * np.pi * freq * t))
    elif wave_type == 'sine':
        wave = np.sin(2 * np.pi * freq * t)
    elif wave_type == 'noise':
        wave = np.random.uniform(-1, 1, n)
    else:
        wave = np.sin(2 * np.pi * freq * t)
    # Envelope
    env = np.ones(n)
    fade = min(int(n * 0.1), 500)
    if fade > 0:
        env[:fade] = np.linspace(0, 1, fade)
        env[-fade:] = np.linspace(1, 0, fade)
    wave = (wave * env * volume * 32767).astype(np.int16)
    stereo = np.column_stack([wave, wave])
    return pygame.sndarray.make_sound(stereo)

def make_fanfare():
    """Multi-note fanfare."""
    notes = [(523, 120), (659, 120), (784, 120), (1047, 300)]
    chunks = []
    for freq, dur in notes:
        n = int(SAMPLE_RATE * dur / 1000)
        t = np.linspace(0, dur / 1000, n, endpoint=False)
        wave = np.sign(np.sin(2 * np.pi * freq * t))
        env = np.ones(n)
        fade = min(int(n * 0.15), 300)
        if fade > 0:
            env[:fade] = np.linspace(0, 1, fade)
            env[-fade:] = np.linspace(1, 0, fade)
        chunks.append(wave * env)
    full = np.concatenate(chunks)
    full = (full * 0.4 * 32767).astype(np.int16)
    stereo = np.column_stack([full, full])
    return pygame.sndarray.make_sound(stereo)

