# ─── CRT Surface helpers ───────────────────────────────────────────────────────

def make_scanline_surface(w, h):
    surf = pygame.Surface((w, h), pygame.SRCALPHA)
    for y in range(0, h, 2):
        pygame.draw.line(surf, (0, 0, 0, 60), (0, y), (w, y))
    return surf

def make_vignette_surface(w, h):
    surf = pygame.Surface((w, h), pygame.SRCALPHA)
    cx, cy = w // 2, h // 2
    for r in range(max(w, h), 0, -2):
        alpha = max(0, int(180 * (r / max(w, h)) ** 2))
        alpha = max(0, 180 - alpha)
        if alpha > 0:
            pass  # skip per-pixel for performance
    # Simple corner darkening via gradient rects
    for i in range(80):
        a = int(i * 1.5)
        pygame.draw.rect(surf, (0, 0, 0, a), (i, i, w - 2*i, h - 2*i), 1)
    return surf

SCANLINES = make_scanline_surface(SCREEN_W, SCREEN_H)
