# ─── Particle system ──────────────────────────────────────────────────────────

class Particle:
    def __init__(self, x, y, color):
        self.x = x
        self.y = y
        self.color = color
        angle = random.uniform(0, 2 * math.pi)
        speed = random.uniform(1, 5)
        self.vx = math.cos(angle) * speed
        self.vy = math.sin(angle) * speed
        self.life = random.randint(15, 35)
        self.max_life = self.life
        self.size = random.randint(2, 5)

    def update(self):
        self.x += self.vx
        self.y += self.vy
        self.vy += 0.1
        self.life -= 1

    def draw(self, surf):
        alpha = int(255 * self.life / self.max_life)
        r = max(0, min(255, self.color[0]))
        g = max(0, min(255, self.color[1]))
        b = max(0, min(255, self.color[2]))
        s = pygame.Surface((self.size * 2, self.size * 2), pygame.SRCALPHA)
        pygame.draw.rect(s, (r, g, b, alpha), (0, 0, self.size * 2, self.size * 2))
        surf.blit(s, (int(self.x) - self.size, int(self.y) - self.size))

# ─── Ball trail ───────────────────────────────────────────────────────────────

class BallTrail:
    def __init__(self):
        self.positions = []

    def add(self, x, y):
        self.positions.append([x, y, 8])

    def update(self):
        for p in self.positions:
            p[2] -= 1
        self.positions = [p for p in self.positions if p[2] > 0]

    def draw(self, surf):
        for p in self.positions:
            alpha = int(255 * p[2] / 8)
            size = max(1, p[2] // 2)
            s = pygame.Surface((size * 2, size * 2), pygame.SRCALPHA)
            pygame.draw.rect(s, (200, 200, 255, alpha), (0, 0, size * 2, size * 2))
            surf.blit(s, (int(p[0]) - size, int(p[1]) - size))

# ─── Brick ────────────────────────────────────────────────────────────────────

class Brick:
    def __init__(self, x, y, w, h, color):
        self.rect = pygame.Rect(x, y, w, h)
        self.color = color
        self.alive = True
        self.pulse = random.uniform(0, math.pi * 2)

    def update(self):
        self.pulse += 0.05

    def draw(self, surf):
        if not self.alive:
            return
        pulse_val = int(20 * math.sin(self.pulse))
        r = max(0, min(255, self.color[0] + pulse_val))
        g = max(0, min(255, self.color[1] + pulse_val))
        b = max(0, min(255, self.color[2] + pulse_val))
        col = (r, g, b)
        pygame.draw.rect(surf, col, self.rect)
        pygame.draw.rect(surf, WHITE, self.rect, 1)
        # RGB bleed effect
        bleed = pygame.Surface((self.rect.w + 4, self.rect.h + 4), pygame.SRCALPHA)
        bleed.fill((r, g, b, 30))
        surf.blit(bleed, (self.rect.x - 2, self.rect.y - 2))

# ─── Paddle ───────────────────────────────────────────────────────────────────

class Paddle:
    def __init__(self):
        self.base_w = 100
        self.h = 12
        self.x = SCREEN_W // 2 - self.base_w // 2
        self.y = SCREEN_H - 50
        self.w = self.base_w
        self.squish = 0.0  # 0..1 squish amount
        self.squish_dir = 0  # 1=stretch, -1=squish

    def update(self, keys, mouse_x, use_mouse):
        if use_mouse:
            self.x = mouse_x - self.w // 2
        else:
            speed = 7
            if keys[pygame.K_LEFT]:
                self.x -= speed
            if keys[pygame.K_RIGHT]:
                self.x += speed
        # Clamp
        wall = 15
        self.x = max(wall, min(SCREEN_W - wall - self.w, self.x))
        # Squish animation
        if self.squish > 0:
            self.squish -= 0.08
            self.squish = max(0, self.squish)

    def hit(self):
        self.squish = 1.0

    @property
    def rect(self):
        squish_px = int(self.squish * 20)
        w = self.base_w + squish_px
        h = self.h - int(self.squish * 4)
        x = self.x - squish_px // 2
        return pygame.Rect(x, self.y, w, max(4, h))

    def draw(self, surf):
        r = self.rect
        pygame.draw.rect(surf, WHITE, r)
        # Glow
        glow = pygame.Surface((r.w + 8, r.h + 8), pygame.SRCALPHA)
        glow.fill((200, 200, 255, 40))
        surf.blit(glow, (r.x - 4, r.y - 4))

# ─── Ball ─────────────────────────────────────────────────────────────────────

class Ball:
    def __init__(self, speed=5):
        self.size = 8
        self.reset(speed)

    def reset(self, speed=5):
        self.x = float(SCREEN_W // 2)
        self.y = float(SCREEN_H - 100)
        angle = random.uniform(-math.pi * 0.7, -math.pi * 0.3)
        self.vx = math.cos(angle) * speed
        self.vy = math.sin(angle) * speed
        self.speed = speed
        self.active = False

    def launch(self):
        self.active = True

    def update(self, paddle, bricks, particles, trail):
        if not self.active:
            self.x = paddle.rect.centerx
            self.y = paddle.rect.top - self.size
            return None  # no event

        trail.add(self.x, self.y)
        self.x += self.vx
        self.y += self.vy

        wall = 15
        event = None

        # Wall collisions
        if self.x - self.size < wall:
            self.x = wall + self.size
            self.vx = abs(self.vx)
            SND_WALL.play()
        if self.x + self.size > SCREEN_W - wall:
            self.x = SCREEN_W - wall - self.size
            self.vx = -abs(self.vx)
            SND_WALL.play()
        if self.y - self.size < 40:  # top wall
            self.y = 40 + self.size
            self.vy = abs(self.vy)
            SND_WALL.play()

        # Bottom (death)
        if self.y > SCREEN_H + 20:
            event = 'death'
            return event

        # Paddle collision
        pr = paddle.rect
        ball_rect = pygame.Rect(self.x - self.size, self.y - self.size,
                                self.size * 2, self.size * 2)
        if ball_rect.colliderect(pr) and self.vy > 0:
            self.vy = -abs(self.vy)
            # Angle based on hit position
            rel = (self.x - pr.centerx) / (pr.w / 2)
            rel = max(-0.9, min(0.9, rel))
            angle = rel * math.pi * 0.4 - math.pi / 2
            spd = math.sqrt(self.vx ** 2 + self.vy ** 2)
            self.vx = math.cos(angle) * spd
            self.vy = math.sin(angle) * spd
            paddle.hit()
            SND_PADDLE.play()

        # Brick collisions
        for brick in bricks:
            if not brick.alive:
                continue
            br = brick.rect
            ball_rect = pygame.Rect(self.x - self.size, self.y - self.size,
                                    self.size * 2, self.size * 2)
            if ball_rect.colliderect(br):
                brick.alive = False
                # Determine bounce direction
                overlap_left = (self.x + self.size) - br.left
                overlap_right = br.right - (self.x - self.size)
                overlap_top = (self.y + self.size) - br.top
                overlap_bottom = br.bottom - (self.y - self.size)
                min_overlap = min(overlap_left, overlap_right, overlap_top, overlap_bottom)
                if min_overlap == overlap_top or min_overlap == overlap_bottom:
                    self.vy = -self.vy
                else:
                    self.vx = -self.vx
                # Particles
                for _ in range(12):
                    particles.append(Particle(br.centerx, br.centery, brick.color))
                SND_BRICK.play()
                event = 'brick'
                break

        return event

    def draw(self, surf):
        pygame.draw.rect(surf, WHITE,
                         (int(self.x) - self.size, int(self.y) - self.size,
                          self.size * 2, self.size * 2))
        # Glow
        glow = pygame.Surface((self.size * 4, self.size * 4), pygame.SRCALPHA)
        glow.fill((200, 200, 255, 50))
        surf.blit(glow, (int(self.x) - self.size * 2, int(self.y) - self.size * 2))

# ─── Brick grid ───────────────────────────────────────────────────────────────

def make_bricks(level=1):
    bricks = []
    rows = 5
    cols = 10
    wall = 15
    top_offset = 80
    bw = (SCREEN_W - wall * 2 - (cols - 1) * 4) // cols
    bh = 22
    for row in range(rows):
        color = BRICK_COLORS[row % len(BRICK_COLORS)]
        for col in range(cols):
            x = wall + col * (bw + 4)
            y = top_offset + row * (bh + 6)
            bricks.append(Brick(x, y, bw, bh, color))
    return bricks

