def draw_text(surf, text, font, color, x, y, center=False, flicker=False):
    if flicker and random.random() < 0.05:
        color = tuple(max(0, c - 80) for c in color)
    img = font.render(text, False, color)  # False = no antialiasing (pixel look)
    if center:
        x -= img.get_width() // 2
    surf.blit(img, (x, y))
    return img.get_width()

def draw_text_glow(surf, text, font, color, x, y, center=False):
    # Draw glow behind
    glow_col = tuple(min(255, c // 2) for c in color)
    img = font.render(text, False, glow_col)
    if center:
        bx = x - img.get_width() // 2
    else:
        bx = x
    for dx, dy in [(-2, 0), (2, 0), (0, -2), (0, 2)]:
        surf.blit(img, (bx + dx, y + dy))
    draw_text(surf, text, font, color, x, y, center)

# ─── CRT warp effect ──────────────────────────────────────────────────────────

def apply_crt_warp(surf, amount=3):
    """Subtle barrel distortion approximation using pixel shift."""
    # For performance, just draw curved border lines
    w, h = surf.get_size()
    overlay = pygame.Surface((w, h), pygame.SRCALPHA)
    # Draw curved vignette corners
    for i in range(20):
        alpha = int(i * 6)
        pygame.draw.rect(overlay, (0, 0, 0, alpha),
                         (i, i, w - 2*i, h - 2*i), 1)
    surf.blit(overlay, (0, 0))

# ─── Intro screen ─────────────────────────────────────────────────────────────

def intro_screen():
    SND_HUM.play(-1)
    SND_FANFARE.play()
    start_time = pygame.time.get_ticks()
    duration = 3500
    warp_phase = 0.0

    while True:
        dt = pygame.time.get_ticks() - start_time
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit(); sys.exit()
            if event.type == pygame.KEYDOWN or event.type == pygame.MOUSEBUTTONDOWN:
                return

        screen.fill(BLACK)

        # Phosphor glow background
        bg = pygame.Surface((SCREEN_W, SCREEN_H))
        bg.fill((0, 8, 0))
        screen.blit(bg, (0, 0))

        # Warp animation
        warp_phase += 0.05
        warp_offset = int(math.sin(warp_phase) * 3)

        # Title flicker
        alpha = min(255, int(dt / 500 * 255))
        t_surf = pygame.Surface((SCREEN_W, 120), pygame.SRCALPHA)

        title = "B R E A K O U T"
        flicker = random.random() < 0.1
        col = (0, max(100, 255 - flicker * 120), max(30, 70 - flicker * 40))
        draw_text_glow(t_surf, title, FONT_LARGE, NEON_GREEN,
                       SCREEN_W // 2, 20, center=True)
        screen.blit(t_surf, (warp_offset, SCREEN_H // 2 - 80))

        draw_text(screen, "INSERT COIN", FONT_MED, WHITE,
                  SCREEN_W // 2, SCREEN_H // 2 + 60, center=True,
                  flicker=True)
        draw_text(screen, "PRESS ANY KEY TO START", FONT_SMALL, CYAN,
                  SCREEN_W // 2, SCREEN_H // 2 + 100, center=True)
        draw_text(screen, "ARROW KEYS / MOUSE  |  SPACE TO LAUNCH", FONT_TINY, GRAY,
                  SCREEN_W // 2, SCREEN_H // 2 + 140, center=True)

        # Scanlines
        screen.blit(SCANLINES, (0, 0))
        apply_crt_warp(screen)

        pygame.display.flip()
        clock.tick(FPS)

        if dt > duration:
            return

# ─── Game Over / High Score ────────────────────────────────────────────────────

def game_over_screen(score, high_scores):
    """Classic arcade high score entry."""
    initials = ['A', 'A', 'A']
    cursor_pos = 0
    blink = 0
    ALPHABET = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ'

    # Check if qualifies
    qualifies = len(high_scores) < 5 or score > min(s for _, s in high_scores)

    while True:
        blink += 1
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit(); sys.exit()
            if event.type == pygame.KEYDOWN:
                if qualifies and cursor_pos < 3:
                    if event.key == pygame.K_UP:
                        idx = ALPHABET.index(initials[cursor_pos])
                        initials[cursor_pos] = ALPHABET[(idx + 1) % 26]
                    elif event.key == pygame.K_DOWN:
                        idx = ALPHABET.index(initials[cursor_pos])
                        initials[cursor_pos] = ALPHABET[(idx - 1) % 26]
                    elif event.key == pygame.K_RIGHT or event.key == pygame.K_RETURN:
                        cursor_pos += 1
                    elif event.key == pygame.K_LEFT:
                        cursor_pos = max(0, cursor_pos - 1)
                if cursor_pos >= 3 or not qualifies:
                    if event.key == pygame.K_RETURN or event.key == pygame.K_SPACE:
                        name = ''.join(initials)
                        if qualifies:
                            high_scores.append((name, score))
                            high_scores.sort(key=lambda x: -x[1])
                            high_scores = high_scores[:5]
                        return high_scores

        screen.fill((0, 5, 0))

        draw_text_glow(screen, "GAME OVER", FONT_LARGE, RED,
                       SCREEN_W // 2, 60, center=True)
        draw_text(screen, f"SCORE: {score}", FONT_MED, WHITE,
                  SCREEN_W // 2, 130, center=True)

        draw_text(screen, "HIGH SCORES", FONT_MED, YELLOW,
                  SCREEN_W // 2, 190, center=True)

        pygame.draw.line(screen, YELLOW, (200, 220), (600, 220), 2)

        for i, (name, sc) in enumerate(high_scores[:5]):
            col = NEON_GREEN if sc == score else WHITE
            draw_text(screen, f"{i+1}.  {name}  {sc:06d}", FONT_SMALL, col,
                      SCREEN_W // 2, 235 + i * 35, center=True)

        if qualifies and cursor_pos < 3:
            draw_text(screen, "ENTER YOUR INITIALS:", FONT_SMALL, CYAN,
                      SCREEN_W // 2, 430, center=True)
            # Draw initials with cursor
            for i, ch in enumerate(initials):
                x = SCREEN_W // 2 - 60 + i * 50
                y = 465
                col = WHITE
                if i == cursor_pos and (blink // 15) % 2 == 0:
                    col = YELLOW
                    pygame.draw.rect(screen, YELLOW, (x - 5, y - 2, 40, 38), 2)
                draw_text(screen, ch, FONT_LARGE, col, x, y)
            draw_text(screen, "UP/DOWN: CHANGE  RIGHT/ENTER: NEXT", FONT_TINY, GRAY,
                      SCREEN_W // 2, 520, center=True)
        else:
            draw_text(screen, "PRESS ENTER TO PLAY AGAIN", FONT_SMALL, NEON_GREEN,
                      SCREEN_W // 2, 470, center=True, flicker=True)

        screen.blit(SCANLINES, (0, 0))
        apply_crt_warp(screen)
        pygame.display.flip()
        clock.tick(FPS)

